Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it with no real ports or processes.

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

### Example test class

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 3,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var result = body.GetProperty("result");
        Assert.False(result.GetProperty("isError").GetBoolean());
    }
}
```

### Key points

- **No real server** — `WebApplicationFactory` hosts your full ASP.NET Core pipeline in-process (middleware, DI, routing — all of it).
- **Swap dependencies** by overriding `CreateHost`/`ConfigureWebHost` on the factory to replace services (databases, external APIs) with fakes.
- **`Program` must be visible** — add `public partial class Program { }` to your server project or use `[assembly: InternalsVisibleTo("YourTestProject")]`.
- Adjust `"/mcp"` to match your actual MCP endpoint path.

### SSE (Streamable HTTP)

If your server uses `Streamable HTTP` with SSE responses, read the stream directly:

```csharp
var response = await _client.PostAsync("/mcp", content);
using var stream = await response.Content.ReadAsStreamAsync();
using var reader = new StreamReader(stream);

var events = new List<string>();
while (await reader.ReadLineAsync() is { } line)
{
    if (line.StartsWith("data: "))
        events.Add(line[6..]);
}
```

This gives you full protocol-level integration tests with zero network overhead.
